1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	const CAP_MULTIPLIER = 2;
4	
5	type ItemCatalogEntry = { basePremium: number; insuranceValue: number };
6	
7	const ITEM_CATALOG: Record<string, ItemCatalogEntry> = {
8	  sword:     { basePremium: 100, insuranceValue: 1000 },
9	  amulet:    { basePremium:  60, insuranceValue:  600 },
10	  staff:     { basePremium:  80, insuranceValue:  800 },
11	  potion:    { basePremium:  40, insuranceValue:  400 },
12	  rune:      { basePremium:  25, insuranceValue:  250 },
13	  moonstone: { basePremium:  25, insuranceValue:  250 },
14	};
15	
16	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
17	type Customer = { yearsWithMHPCO: number };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Damage = { itemType: string; amount: number };
20	type Incident = { cause: string; damages: Damage[] };
21	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
22	type Step = QuoteStep | ClaimStep;
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	const basePremiumFor = (item: Item): number => ITEM_CATALOG[item.type].basePremium;
26	
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_PREMIUM = 60;
29	
30	const sumBy = <T>(xs: T[], f: (x: T) => number): number =>
31	  xs.reduce((sum, x) => sum + f(x), 0);
32	
33	const groupByType = (items: Item[]): Item[][] => {
34	  const groups = new Map<string, Item[]>();
35	  for (const item of items) {
36	    const group = groups.get(item.type) ?? [];
37	    group.push(item);
38	    groups.set(item.type, group);
39	  }
40	  return [...groups.values()];
41	};
42	
43	const basePremiumForGroup = (group: Item[]): number =>
44	  group.length === COMPONENT_BLOCK_SIZE
45	    ? COMPONENT_BLOCK_PREMIUM
46	    : sumBy(group, basePremiumFor);
47	
48	const totalBasePremium = (items: Item[]): number =>
49	  sumBy(groupByType(items), basePremiumForGroup);
50	
51	const CURSE_SURCHARGE_RATE = 0.5;
52	const HIGH_ENCHANTMENT_RATE = 0.3;
53	const HIGH_ENCHANTMENT_THRESHOLD = 5;
54	const FIRST_INSURANCE_RATE = 0.1;
55	const LOYALTY_DISCOUNT_RATE = -0.2;
56	const LOYALTY_YEARS_THRESHOLD = 2;
57	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
58	
59	type PolicyContext = { customer: Customer; isFollowUp: boolean };
60	
61	const isCursed = (item: Item): boolean => item.cursed === true;
62	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
63	const isHighlyEnchanted = (item: Item): boolean =>
64	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
65	
66	type Modifier<T> = { applies: (subject: T) => boolean; rate: number };
67	
68	const sumApplicableRates = <T>(modifiers: Modifier<T>[], subject: T): number =>
69	  sumBy(modifiers, ({ applies, rate }) => (applies(subject) ? rate : 0));
70	
71	const ITEM_SURCHARGES: Modifier<Item>[] = [
72	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
73	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
74	];
75	
76	const isLoyalCustomer = (ctx: PolicyContext): boolean =>
77	  ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
78	const isFollowUpContract = (ctx: PolicyContext): boolean => ctx.isFollowUp;
79	
80	// First-insurance rate applies to every quote unconditionally;
81	// other policy modifiers are conditional on the customer/contract context.
82	const POLICY_MODIFIERS: Modifier<PolicyContext>[] = [
83	  { applies: isLoyalCustomer, rate: LOYALTY_DISCOUNT_RATE },
84	  { applies: isFollowUpContract, rate: FOLLOW_UP_DISCOUNT_RATE },
85	];
86	
87	const policyAdjustment = (baseTotal: number, ctx: PolicyContext): number =>
88	  baseTotal * (FIRST_INSURANCE_RATE + sumApplicableRates(POLICY_MODIFIERS, ctx));
89	
90	const itemSurchargeFor = (item: Item): number =>
91	  basePremiumFor(item) * sumApplicableRates(ITEM_SURCHARGES, item);
92	
93	const itemSurchargesTotal = (items: Item[]): number =>
94	  sumBy(items, itemSurchargeFor);
95	
96	const premiumFor = (items: Item[], ctx: PolicyContext): number => {
97	  const baseTotal = totalBasePremium(items);
98	  return Math.ceil(
99	    baseTotal +
100	      itemSurchargesTotal(items) +
101	      policyAdjustment(baseTotal, ctx) +
102	      PROCESSING_FEE,
103	  );
104	};
105	
106	const insuranceValueFor = (item: Item): number => ITEM_CATALOG[item.type].insuranceValue;
107	
108	const insuranceSumFor = (items: Item[]): number => sumBy(items, insuranceValueFor);
109	
110	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
111	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
112	
113	const triggersHighEnchantmentClause = (item: Item): boolean =>
114	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
115	
116	const reimbursableAmount = (damage: Damage, item: Item): number =>
117	  triggersHighEnchantmentClause(item)
118	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
119	    : damage.amount;
120	
121	const payoutForDamage = (damage: Damage, item: Item): number =>
122	  reimbursableAmount(damage, item) - DEDUCTIBLE;
123	
124	const policyItemFor = (policy: QuoteStep, damage: Damage): Item =>
125	  policy.items.find((item) => item.type === damage.itemType)!;
126	
127	const capFor = (items: Item[]): number =>
128	  insuranceSumFor(items) * CAP_MULTIPLIER;
129	
130	const countBy = <T>(xs: T[], key: (x: T) => string): Map<string, number> => {
131	  const counts = new Map<string, number>();
132	  for (const x of xs) {
133	    const k = key(x);
134	    counts.set(k, (counts.get(k) ?? 0) + 1);
135	  }
136	  return counts;
137	};
138	
139	const validateDamageCounts = (step: ClaimStep, policy: QuoteStep): void => {
140	  const itemCounts = countBy(policy.items, (i) => i.type);
141	  const damageCounts = countBy(step.incident.damages, (d) => d.itemType);
142	  for (const [type, count] of damageCounts) {
143	    if (count > (itemCounts.get(type) ?? 0)) {
144	      throw new Error(`claim references more ${type} damages than the policy covers`);
145	    }
146	  }
147	};
148	
149	const claimResultFor = (
150	  step: ClaimStep,
151	  policy: QuoteStep,
152	): { payout: number; remainingCap: number } => {
153	  validateDamageCounts(step, policy);
154	  const payout = sumBy(step.incident.damages, (damage) =>
155	    payoutForDamage(damage, policyItemFor(policy, damage)),
156	  );
157	  return { payout, remainingCap: capFor(policy.items) - payout };
158	};
159	
160	const quoteResultFor = (step: QuoteStep, ctx: PolicyContext) => ({
161	  premium: premiumFor(step.items, ctx),
162	});
163	
164	const policyContextFor = (scenario: Scenario, stepIndex: number): PolicyContext => ({
165	  customer: scenario.customer,
166	  isFollowUp: stepIndex > 0,
167	});
168	
169	const policyReferencedBy = (scenario: Scenario, claim: ClaimStep): QuoteStep =>
